final class FWFAccusPurchTableType_Extension
{
}

Method.Source:
boolean canInvoiceBeUpdated(boolean _excludePending)
{
    boolean ok = next canInvoiceBeUpdated(_excludePending);

    if (!ok && this.purchTable.FWFAccusStatus == NoYes::Yes)
    {
        ok = FWFAccusHelper::purchCanAccusCreditNoteBeUpdated(this.purchTable.PurchId);
    }

    return ok;
}
